```class Solution {
    public String countOfAtoms(String formula) {
        Map<String, Integer> map = new HashMap<>();
        formula = formula.replaceAll("\\(", " (").replaceAll("\\)", " )");
        String[] parts = formula.split(" ");
        for (String part : parts) {
            int i = 0;
            while (i < part.length()) {
                if (Character.isUpperCase(part.charAt(i))) {
                    int j = i + 1;
                    while (j < part.length() && Character.isLowerCase(part.charAt(j))) {
                        j++;
                    }
                    String atom = part.substring(i, j);
                    i = j;
                    while (i < part.length() && Character.isDigit(part.charAt(i))) {
                        i++;
                    }
                    int count = i == part.length() ? 1 : Integer.parseInt(part.substring(i));
                    map.put(atom, map.getOrDefault(atom, 0) + count);
                } else {
                    i++;
                }
            }
        }
        StringBuilder sb = new StringBuilder();
        List<String> atoms = new ArrayList<>(map.keySet());
        Collections.sort(atoms);
        for (String atom : atoms) {
            sb.append(atom);
            int count = map.get(atom);
            if (count > 1) {
                sb.append(count);
            }
        }
        return sb.toString();
    }
}```
